#[derive(Serialize)]
pub struct BettiValidationResult {
    pub is_valid: bool,
    pub error: Option<String>,
    pub ast_json: Option<String>,
}

struct BettiValidator {
    pub is_valid: bool,
    pub error_msg: Option<String>,
}

impl BettiValidator {
    fn new() -> Self {
        Self {
            is_valid: true,
            error_msg: None,
        }
    }

    fn report_error(&mut self, msg: &str) {
        if self.is_valid {
            self.is_valid = false;
            self.error_msg = Some(msg.to_string());
        }
    }

    fn validate_module_exports(&mut self, module: &Module) {
        for item in &module.body {
            if let ModuleItem::ModuleDecl(decl) = item {
                self.validate_module_decl(decl);
            }
        }
    }

    fn validate_module_decl(&mut self, decl: &ModuleDecl) {
        match decl {
            ModuleDecl::ExportDecl(ExportDecl { decl, .. }) => {
                if let Decl::Fn(fn_decl) = decl {
                    self.validate_fn_decl(fn_decl, "export declaration");
                }
            }
            ModuleDecl::ExportDefaultDecl(ExportDefaultDecl { decl, .. }) => {
                if let DefaultDecl::Fn(fn_expr) = decl {
                    self.validate_fn_expr(fn_expr, "export default");
                }
            }
            ModuleDecl::ExportDefaultExpr(ExportDefaultExpr { expr, .. }) => {
                if let Expr::Fn(fn_expr) = &**expr {
                    self.validate_fn_expr(fn_expr, "export default expression");
                }
            }
            _ => {}
        }
    }

    fn validate_fn_decl(&mut self, n: &FnDecl, label: &str) {
        let name = n.ident.sym.to_string();
        self.validate_function(&n.function, &name, label);
    }

    fn validate_fn_expr(&mut self, n: &FnExpr, label: &str) {
        let name = n
            .ident
            .as_ref()
            .map(|i| i.sym.to_string())
            .unwrap_or_else(|| "<anonymous>".to_string());
        self.validate_function(&n.function, &name, label);
    }

    fn validate_function(&mut self, function: &Function, name: &str, label: &str) {
        let is_entrypoint = name == "main" || name == "handler" || name == "app" || name == "default" || name == "<anonymous>";
        if !is_entrypoint {
            return;
        }

        if function.params.len() > 1 {
            self.report_error(&format!(
                "Gnosis TS bridge — entrypoint `{name}` ({label}): at most one parameter is allowed.\n\
                 Hint: `gnode run` passes at most one JSON input to the entrypoint."
            ));
            return;
        }

        for param in &function.params {
            if !param.pat.is_ident() {
                self.report_error(&format!(
                    "Gnosis TS bridge — entrypoint `{name}` ({label}): parameters must be simple identifiers (no destructuring)."
                ));
                return;
            }
        }

        let mut return_count = 0;
        if let Some(body) = &function.body {
            for stmt in &body.stmts {
                if stmt.is_return_stmt() {
                    return_count += 1;
                }
            }
        }

        if return_count == 0 {
            self.report_error(&format!(
                "Gnosis TS bridge — entrypoint `{name}` ({label}): the exported function body must contain exactly one `return` statement.\n\
                 Void / implicit-undefined returns are rejected for bridge entrypoints.\n\
                 Remediation: return an exit code number, a string payload, or structured JSON; or move work into non-exported helpers and keep the entrypoint as a single `return`.\n\
                 Note: non-exported top-level functions and nested callbacks are not subject to this rule.\n\
                 Source byte offset (function span lo): {}",
                function.span.lo.0
            ));
        } else if return_count > 1 {
            self.report_error(&format!(
                "Gnosis TS bridge — entrypoint `{name}` ({label}): at most one `return` statement is supported in the entrypoint body."
            ));
        }
    }
}

impl Visit for BettiValidator {
    fn visit_program(&mut self, program: &Program) {
        match program {
            Program::Module(module) => {
                self.validate_module_exports(module);
            }
            Program::Script(_) => {}
        }
    }
}

pub fn inner_validate_and_parse_typescript(source_text: &str) -> BettiValidationResult {
    let cm: Arc<SourceMap> = Default::default();
    let fm = cm.new_source_file(FileName::Custom("bridge.ts".into()).into(), source_text.to_string());
    let lexer = Lexer::new(
        Syntax::Typescript(Default::default()),
        Default::default(),
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let program = match parser.parse_program() {
        Ok(p) => p,
        Err(e) => {
            return BettiValidationResult {
                is_valid: false,
                error: Some(format!("Parse error {:?}", e.into_kind())),
                ast_json: None,
            };
        }
    };
    
    let mut validator = BettiValidator::new();
    program.visit_with(&mut validator);

    if !validator.is_valid {
        return BettiValidationResult {
            is_valid: false,
            error: validator.error_msg,
            ast_json: None,
        };
    }

    let ast_json = serde_json::to_string(&program).unwrap();

    BettiValidationResult {
        is_valid: true,
        error: None,
        ast_json: Some(ast_json),
    }
}

#[wasm_bindgen]
pub fn validate_and_parse_typescript(source_text: &str) -> JsValue {
    let result = inner_validate_and_parse_typescript(source_text);
    serde_wasm_bindgen::to_value(&result).unwrap()
}

#[derive(Serialize)]
pub struct ImportSpecifier {
    pub value: String,
    pub start: u32,
    pub end: u32,
}

#[derive(Serialize)]
pub struct FunctionRecordResult {
    pub local_name: String,
    pub start: u32,
    pub end: u32,
}

#[derive(Serialize)]
pub struct FunctionGraphResult {
    pub functions_by_local_name: std::collections::HashMap<String, FunctionRecordResult>,
    pub exports_by_name: std::collections::HashMap<String, String>,
}

struct FunctionGraphExtractor {
    pub result: FunctionGraphResult,
    pub anonymous_count: u32,
}

impl FunctionGraphExtractor {
    fn next_anon_name(&mut self) -> String {
        let name = format!("__default_export_{}", self.anonymous_count);
        self.anonymous_count += 1;
        name
    }

    fn add_function(&mut self, local_name: String, start: u32, end: u32) {
        self.result.functions_by_local_name.insert(
            local_name.clone(),
            FunctionRecordResult { local_name, start, end },
        );
    }
}

impl Visit for FunctionGraphExtractor {
    fn visit_module_item(&mut self, item: &ModuleItem) {
        match item {
            ModuleItem::ModuleDecl(decl) => match decl {
                ModuleDecl::ExportDecl(export) => {
                    match &export.decl {
                        Decl::Fn(fn_decl) => {
                            let name = fn_decl.ident.sym.to_string();
                            self.add_function(name.clone(), fn_decl.function.span.lo.0 - 1, fn_decl.function.span.hi.0 - 1);
                            self.result.exports_by_name.insert(name.clone(), name);
                        }
                        Decl::Var(var_decl) => {
                            for decl in &var_decl.decls {
                                if let Pat::Ident(ident) = &decl.name {
                                    if let Some(init) = &decl.init {
                                        if init.is_arrow() || init.is_fn_expr() {
                                            let name = ident.id.sym.to_string();
                                            self.add_function(name.clone(), init.span_lo().0 - 1, init.span_hi().0 - 1);
                                            self.result.exports_by_name.insert(name.clone(), name);
                                        }
                                    }
                                }
                            }
                        }
                        _ => {}
                    }
                }
                ModuleDecl::ExportDefaultDecl(export) => {
                    match &export.decl {
                        DefaultDecl::Fn(fn_expr) => {
                            let name = if let Some(ident) = &fn_expr.ident {
                                ident.sym.to_string()
                            } else {
                                self.next_anon_name()
                            };
                            self.add_function(name.clone(), fn_expr.function.span.lo.0 - 1, fn_expr.function.span.hi.0 - 1);
                            self.result.exports_by_name.insert("default".to_string(), name);
                        }
                        _ => {}
                    }
                }
                ModuleDecl::ExportDefaultExpr(export) => {
                    if let Expr::Ident(ident) = &*export.expr {
                        self.result.exports_by_name.insert("default".to_string(), ident.sym.to_string());
                    } else if export.expr.is_arrow() || export.expr.is_fn_expr() {
                        let name = self.next_anon_name();
                        self.add_function(name.clone(), export.expr.span_lo().0 - 1, export.expr.span_hi().0 - 1);
                        self.result.exports_by_name.insert("default".to_string(), name);
                    }
                }
                ModuleDecl::ExportNamed(export) => {
                    if export.src.is_none() {
                        for specifier in &export.specifiers {
                            if let ExportSpecifier::Named(named) = specifier {
                                let orig = match &named.orig {
                                    ModuleExportName::Ident(ident) => ident.sym.to_string(),
                                    ModuleExportName::Str(s) => s.value.to_string_lossy().into_owned(),
                                };
                                let export_name = if let Some(exported) = &named.exported {
                                    match exported {
                                        ModuleExportName::Ident(ident) => ident.sym.to_string(),
                                        ModuleExportName::Str(s) => s.value.to_string_lossy().into_owned(),
                                    }
                                } else {
                                    orig.clone()
                                };
                                self.result.exports_by_name.insert(export_name, orig);
                            }
                        }
                    }
                }
                _ => {}
            },
            ModuleItem::Stmt(stmt) => match stmt {
                Stmt::Decl(Decl::Fn(fn_decl)) => {
                    let name = fn_decl.ident.sym.to_string();
                    self.add_function(name.clone(), fn_decl.function.span.lo.0 - 1, fn_decl.function.span.hi.0 - 1);
                }
                Stmt::Decl(Decl::Var(var_decl)) => {
                    for decl in &var_decl.decls {
                        if let Pat::Ident(ident) = &decl.name {
                            if let Some(init) = &decl.init {
                                if init.is_arrow() || init.is_fn_expr() {
                                    let name = ident.id.sym.to_string();
                                    self.add_function(name.clone(), init.span_lo().0 - 1, init.span_hi().0 - 1);
                                }
                            }
                        }
                    }
                }
                _ => {}
            },
        }
        item.visit_children_with(self);
    }
}

pub fn inner_extract_function_graph(source_text: &str) -> Option<FunctionGraphResult> {
    let cm: Arc<SourceMap> = Default::default();
    let fm = cm.new_source_file(FileName::Custom("bridge.ts".into()).into(), source_text.to_string());
    let lexer = Lexer::new(
        Syntax::Typescript(Default::default()),
        Default::default(),
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let program = match parser.parse_program() {
        Ok(p) => p,
        Err(_) => return None,
    };
    
    let mut extractor = FunctionGraphExtractor {
        result: FunctionGraphResult {
            functions_by_local_name: std::collections::HashMap::new(),
            exports_by_name: std::collections::HashMap::new(),
        },
        anonymous_count: 0,
    };
    program.visit_with(&mut extractor);

    Some(extractor.result)
}

#[wasm_bindgen]
pub fn extract_function_graph(source_text: &str) -> JsValue {
    let result = inner_extract_function_graph(source_text);
    match result {
        Some(r) => serde_wasm_bindgen::to_value(&r).unwrap(),
        None => JsValue::NULL,
    }
}

struct ImportExtractor {
    pub imports: Vec<ImportSpecifier>,
}

impl Visit for ImportExtractor {
    fn visit_import_decl(&mut self, n: &ImportDecl) {
        self.imports.push(ImportSpecifier {
            value: n.src.value.to_string_lossy().into_owned(),
            start: n.src.span.lo.0 - 1,
            end: n.src.span.hi.0 - 1,
        });
        n.visit_children_with(self);
    }

    fn visit_named_export(&mut self, n: &NamedExport) {
        if let Some(src) = &n.src {
            self.imports.push(ImportSpecifier {
                value: src.value.to_string_lossy().into_owned(),
                start: src.span.lo.0 - 1,
                end: src.span.hi.0 - 1,
            });
        }
        n.visit_children_with(self);
    }
    
    fn visit_export_all(&mut self, n: &ExportAll) {
        self.imports.push(ImportSpecifier {
            value: n.src.value.to_string_lossy().into_owned(),
            start: n.src.span.lo.0 - 1,
            end: n.src.span.hi.0 - 1,
        });
        n.visit_children_with(self);
    }

    fn visit_call_expr(&mut self, n: &CallExpr) {
        if let Callee::Import(_) = &n.callee {
            if let Some(arg) = n.args.first() {
                if let Expr::Lit(Lit::Str(s)) = &*arg.expr {
                    self.imports.push(ImportSpecifier {
                        value: s.value.to_string_lossy().into_owned(),
                        start: s.span.lo.0 - 1,
                        end: s.span.hi.0 - 1,
                    });
                }
            }
        }
        n.visit_children_with(self);
    }
}

pub fn inner_extract_imports(source_text: &str) -> Option<Vec<ImportSpecifier>> {
    let cm: Arc<SourceMap> = Default::default();
    let fm = cm.new_source_file(FileName::Custom("bridge.ts".into()).into(), source_text.to_string());
    let lexer = Lexer::new(
        Syntax::Typescript(Default::default()),
        Default::default(),
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let program = match parser.parse_program() {
        Ok(p) => p,
        Err(_) => return None,
    };
    
    let mut extractor = ImportExtractor { imports: Vec::new() };
    program.visit_with(&mut extractor);

    Some(extractor.imports)
}

#[wasm_bindgen]
pub fn extract_imports(source_text: &str) -> JsValue {
    let result = inner_extract_imports(source_text);
    match result {
        Some(r) => serde_wasm_bindgen::to_value(&r).unwrap(),
        None => JsValue::NULL,
    }
}

#[derive(Serialize)]
pub struct TranspileResult {
    pub code: String,
    pub error: Option<String>,
}

pub fn inner_transpile_typescript(source_text: &str, _jsx: bool) -> TranspileResult {
    let cm: Lrc<SourceMap> = Default::default();
    let fm = cm.new_source_file(
        FileName::Custom("input.ts".into()).into(),
        source_text.to_string(),
    );

    let ts_syntax = Default::default();
    let lexer = Lexer::new(
        Syntax::Typescript(ts_syntax),
        EsVersion::Es2022,
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let mut program = match parser.parse_program() {
        Ok(p) => p,
        Err(e) => {
            return TranspileResult {
                code: String::new(),
                error: Some(format!("Parse error: {:?}", e.into_kind())),
            };
        }
    };

    GLOBALS.set(&Globals::new(), || {
        let unresolved_mark = Mark::new();
        let top_level_mark = Mark::new();
        let mut pass = typescript::strip(unresolved_mark, top_level_mark);
        pass.process(&mut program);
    });

    let mut buf = Vec::new();
    {
        let wr = JsWriter::new(cm.clone(), "\n", &mut buf, None);
        let mut emitter = Emitter {
            cfg: swc_ecma_codegen::Config::default()
                .with_target(EsVersion::Es2022)
                .with_ascii_only(false)
                .with_minify(false),
            cm: cm.clone(),
            comments: None,
            wr: Box::new(wr),
        };

        if let Err(e) = emitter.emit_program(&program) {
            return TranspileResult {
                code: String::new(),
                error: Some(format!("Codegen error: {e}")),
            };
        }
    }

    let code = String::from_utf8(buf).unwrap_or_default();
    TranspileResult { code, error: None }
}

#[wasm_bindgen]
pub fn transpile_typescript(source_text: &str, jsx: bool) -> JsValue {
    let result = inner_transpile_typescript(source_text, jsx);
    serde_wasm_bindgen::to_value(&result).unwrap()
}

#[derive(Serialize)]
pub struct SerializedGnosisResult {
    #[serde(rename = "exportName")]
    pub export_name: String,
    #[serde(rename = "entryNodeId")]
    pub entry_node_id: String,
    #[serde(rename = "sourceFilePath")]
    pub source_file_path: String,
    #[serde(rename = "ggSource")]
    pub gg_source: String,
    #[serde(rename = "topologySource")]
    pub topology_source: String,
    pub ast: GraphAST,
    #[serde(rename = "nodePlans")]
    pub node_plans: Vec<BridgeNodePlan>,
    pub schedule: Vec<BridgeWave>,
    #[serde(rename = "runtimeBindingNames")]
    pub runtime_binding_names: Vec<String>,
    #[serde(rename = "runtimeModuleSource")]
    pub runtime_module_source: Option<String>,
}

pub fn inner_compile_gnosis_bridge(
    source_text: &str,
    source_file_path: &str,
    target_export_name: &str,
    target_language: Option<String>,
) -> Result<SerializedGnosisResult, String> {
    let language_origin = match target_language.as_deref() {
        Some("typescript") | Some("ts") => LanguageOrigin::Typescript,
        Some("javascript") | Some("js") => LanguageOrigin::Javascript,
        Some("python") | Some("py") => LanguageOrigin::Python,
        Some("rust") | Some("rs") => LanguageOrigin::Rust,
        Some("go") => LanguageOrigin::Go,
        Some("lean") => LanguageOrigin::Lean,
        _ => LanguageOrigin::default(),
    };

    if language_origin == LanguageOrigin::Lean {
        let parser = crate::lean_parser::LeanParser;
        use crate::polyglot_traits::AstParser;
        let polyglot_fn = parser.parse(source_text, target_export_name)?;
        
        let mut state = CompileState::new(source_text, Default::default(), source_file_path.to_string(), None, target_export_name.to_string());
        let entry_node_id = state.create_node_id("entry", target_export_name);
        
        let entry_plan = BridgeNodePlan::Entry { 
            ghost_mass: None, 
            node_id: entry_node_id.clone(),
            handler_label: "LeanBridgeEntry".to_string(),
            source_location: None,
        };
        state.node_plans.push(entry_plan);
        
        crate::polyglot_compiler::compile_polyglot_function(&polyglot_fn, &mut state)?;
        
        let schedule = build_schedule(&state.operations);
        let ast = build_bridge_ast(&state.node_plans, &state.operations);
        let topology_source = render_topology_source(target_export_name, &state.node_plans, &state.operations);
        
        return Ok(SerializedGnosisResult {
            export_name: target_export_name.to_string(),
            entry_node_id,
            source_file_path: source_file_path.to_string(),
            gg_source: topology_source.clone(), 
            topology_source,
            ast,
            node_plans: state.node_plans,
            schedule,
            runtime_binding_names: state.known_bindings.into_iter().collect(),
            runtime_module_source: None,
        });
    }

    let cm: Lrc<SourceMap> = Default::default();
    let fm = cm.new_source_file(Lrc::new(FileName::Custom("bridge.ts".into())), source_text.to_string());
    let lexer = Lexer::new(
        Syntax::Typescript(Default::default()),
        Default::default(),
        StringInput::from(&*fm),
        None,
    );
    let mut parser = Parser::new_from(lexer);

    let module = parser
        .parse_typescript_module()
        .map_err(|e| format!("Failed to parse module: {:?}", e.into_kind()))?;

    let mut target_fn_opt = None;
    let mut target_span_opt = None;
    let mut found_names = Vec::new();

    for item in &module.body {
        match item {
            ModuleItem::ModuleDecl(ModuleDecl::ExportDecl(export_decl)) => {
                if let Decl::Fn(fn_decl) = &export_decl.decl {
                    let name = fn_decl.ident.sym.to_string();
                    found_names.push(name.clone());
                    if name == target_export_name {
                        target_fn_opt = Some(fn_decl.clone());
                        target_span_opt = Some(export_decl.span);
                        break;
                    }
                } else if let Decl::Var(var_decl) = &export_decl.decl {
                    for decl in &var_decl.decls {
                        if let Pat::Ident(ident) = &decl.name {
                            let name = ident.id.sym.to_string();
                            found_names.push(name.clone());
                            if name == target_export_name {
                                if let Some(init) = &decl.init {
                                    if let Expr::Arrow(arrow) = &**init {
                                        let function = Box::new(Function {
                                            params: arrow.params.iter().map(|p| Param {
                                                span: DUMMY_SP,
                                                decorators: vec![],
                                                pat: p.clone(),
                                            }).collect(),
                                            decorators: vec![],
                                            span: arrow.span,
                                            body: match &*arrow.body {
                                                BlockStmtOrExpr::BlockStmt(b) => Some(b.clone()),
                                                BlockStmtOrExpr::Expr(e) => Some(BlockStmt {
                                                    span: DUMMY_SP,
                                                    stmts: vec![Stmt::Return(ReturnStmt {
                                                        span: DUMMY_SP,
                                                        arg: Some(e.clone()),
                                                    })],
                                                    ctxt: swc_common::SyntaxContext::empty(),
                                                }),
                                            },
                                            is_generator: arrow.is_generator,
                                            is_async: arrow.is_async,
                                            type_params: arrow.type_params.clone(),
                                            return_type: arrow.return_type.clone(),
                                            ctxt: swc_common::SyntaxContext::empty(),
                                        });
                                        target_fn_opt = Some(FnDecl {
                                            ident: ident.id.clone(),
                                            declare: false,
                                            function,
                                        });
                                        target_span_opt = Some(export_decl.span);
                                    } else if let Expr::Fn(fn_expr) = &**init {
                                        target_fn_opt = Some(FnDecl {
                                            ident: ident.id.clone(),
                                            declare: false,
                                            function: fn_expr.function.clone(),
                                        });
                                        target_span_opt = Some(export_decl.span);
                                    }
                                }
                            }
                        }
                    }
                }
            }
            ModuleItem::ModuleDecl(ModuleDecl::ExportDefaultDecl(export_default)) => {
                if target_export_name == "default" {
                    if let DefaultDecl::Fn(fn_expr) = &export_default.decl {
                        let name = fn_expr.ident.as_ref().map(|id| id.sym.to_string()).unwrap_or_else(|| "default".to_string());
                        target_fn_opt = Some(FnDecl {
                            ident: Ident::new(name.into(), DUMMY_SP, Default::default()),
                            declare: false,
                            function: fn_expr.function.clone(),
                        });
                        target_span_opt = Some(export_default.span);
                        break;
                    }
                }
            }
            _ => {}
        }
    }

    let target_fn = target_fn_opt.ok_or_else(|| format!("Export node not found for {}. Found exports: {:?}", target_export_name, found_names))?;
    
    let target_span = target_span_opt.unwrap_or_else(|| target_fn.function.span);

    let mut input_parameter_name = None;
    if target_fn.function.params.len() > 1 {
        return Err("TS bridge entrypoints may accept at most one parameter".to_string());
    }
    if let Some(param) = target_fn.function.params.first() {
        if let Pat::Ident(binding_ident) = &param.pat {
            input_parameter_name = Some(binding_ident.id.sym.to_string());
        } else {
            return Err("TS bridge entrypoint parameters must use a simple identifier".to_string());
        }
    }

    let filename = std::path::Path::new(source_file_path)
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("bridge");
    let prefix = format!("{}_{}", 
        compiler::sanitize_identifier(filename),
        compiler::sanitize_identifier(target_export_name)
    );

    let mut state = CompileState::new(source_text, cm.clone(), source_file_path.to_string(), input_parameter_name, prefix);

    let actual_fn_name = target_fn.ident.sym.to_string();
    let entry_node_id = state.create_node_id("entry", &actual_fn_name);
    let entry_plan = BridgeNodePlan::Entry { ghost_mass: None, 
        node_id: entry_node_id.clone(),
        handler_label: "TsBridgeEntry".to_string(),
        source_location: state.extract_source_location(target_span),
    };
    state.node_plans.push(entry_plan);

    if let Some(body) = &target_fn.function.body {
        for stmt in &body.stmts {
            compile_statement(stmt, &mut state)?;
        }
    } else {
        return Err("Function has no body".to_string());
    }

    if state.operations.is_empty() {
        let ret_node_id = state.create_node_id("return", "void");
        let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
            node_id: ret_node_id.clone(),
            handler_label: "TsBridgeReturn".to_string(),
            expression: BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Null },
            source_location: None,
        };
        state.node_plans.push(ret_plan.clone());
        state.operations.push(BridgeOperation::Return { plan: ret_plan });
    }

    let schedule = build_schedule(&state.operations);
    let ast = build_bridge_ast(&state.node_plans, &state.operations);
    let topology_source = render_topology_source(target_export_name, &state.node_plans, &state.operations);

    Ok(SerializedGnosisResult {
        export_name: target_export_name.to_string(),
        entry_node_id,
        source_file_path: source_file_path.to_string(),
        gg_source: topology_source.clone(), 
        topology_source,
        ast,
        node_plans: state.node_plans,
        schedule,
        runtime_binding_names: state.known_bindings.into_iter().collect(),
        runtime_module_source: None,
    })
}

#[wasm_bindgen]
pub fn compile_gnosis_bridge(
    source_text: &str,
    source_file_path: &str,
    target_export_name: &str,
    target_language: Option<String>,
) -> Result<JsValue, JsValue> {
    let result = inner_compile_gnosis_bridge(source_text, source_file_path, target_export_name, target_language)
        .map_err(|e| JsValue::from_str(&e))?;
    let serializer = serde_wasm_bindgen::Serializer::json_compatible();
    result.serialize(&serializer).map_err(|e| JsValue::from_str(&e.to_string()))
}

#[wasm_bindgen]
pub fn compile_polyglot_fn(polyglot_fn_json: &str) -> Result<JsValue, JsValue> {
    use polyglot_wasm_types::PolyglotFnInput;
    use polyglot_wasm_compiler::compile_polyglot_fn_input;

    let input: PolyglotFnInput = serde_json::from_str(polyglot_fn_json)
        .map_err(|e| JsValue::from_str(&format!("PolyglotFnInput parse error: {e}")))?
        ;

    let result = compile_polyglot_fn_input(&input)
        .map_err(|e| JsValue::from_str(&e))?;

    let serializer = serde_wasm_bindgen::Serializer::json_compatible();
    result.serialize(&serializer).map_err(|e| JsValue::from_str(&e.to_string()))
}

#[wasm_bindgen]
pub fn polyglot_supported_languages() -> JsValue {
    let langs = vec![
        "typescript", "javascript",
        "python", "rust", "go", "java",
        "c", "cpp", "c_sharp", "ruby", "php",
        "bash", "scala", "kotlin", "swift",
        "haskell", "ocaml", "lua", "elixir", "zig",
        "lean",
    ];
    serde_wasm_bindgen::to_value(&langs).unwrap_or(JsValue::NULL)
}

#[wasm_bindgen]
pub fn score_firework_design(design_json: &str) -> Result<JsValue, JsValue> {
    let design: FireworkDesign = serde_json::from_str(design_json)
        .map_err(|e| JsValue::from_str(&format!("FireworkDesign parse error: {e}")))?;
    let score = score_design(&design);
    let serializer = serde_wasm_bindgen::Serializer::json_compatible();
    score
        .serialize(&serializer)
        .map_err(|e| JsValue::from_str(&e.to_string()))
}
